package cl.duoc.vetcontrol.atencion.model;
import jakarta.persistence.*; import java.time.*;
@Entity @Table(name="atenciones")
public class Atencion { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private Long citaId; @Column(nullable=false) private Long mascotaId; @Column(nullable=false) private Long veterinarioId; @Column(nullable=false) private LocalDateTime fechaAtencion; @Column(nullable=false,length=300) private String diagnostico; @Column(nullable=false,length=300) private String tratamiento; @Column(length=500) private String observaciones; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getCitaId(){return citaId;} public void setCitaId(Long citaId){this.citaId=citaId;} public Long getMascotaId(){return mascotaId;} public void setMascotaId(Long mascotaId){this.mascotaId=mascotaId;} public Long getVeterinarioId(){return veterinarioId;} public void setVeterinarioId(Long veterinarioId){this.veterinarioId=veterinarioId;} public LocalDateTime getFechaAtencion(){return fechaAtencion;} public void setFechaAtencion(LocalDateTime fechaAtencion){this.fechaAtencion=fechaAtencion;} public String getDiagnostico(){return diagnostico;} public void setDiagnostico(String diagnostico){this.diagnostico=diagnostico;} public String getTratamiento(){return tratamiento;} public void setTratamiento(String tratamiento){this.tratamiento=tratamiento;} public String getObservaciones(){return observaciones;} public void setObservaciones(String observaciones){this.observaciones=observaciones;} }
